const output = [];

for (const item of $input.all()) {

  const input = item.json;

  const data = Array.isArray(input) ? input[0] : input;

  const sentences = data.sentences || {};

  const merged = [];

  for (const [text, score] of Object.entries(sentences)) {
    merged.push({
      text,
      score,
      type: score > 50 ? "ai" : "human"
    });
  }

  output.push({
    json: {
      sentences: merged
    }
  });
}

return output;
